---@class UIHeroRaceList
local UIHeroRaceList = LxClass("UIHeroRaceList",nil)

UIHeroRaceList.ALL_RACE_REFID = 0

UIHeroRaceList.TYPE_NORMAL = 0          -- 不带白色背景
UIHeroRaceList.TYPE_SHOWBG = 1          -- 带白色背景

function UIHeroRaceList:UIHeroRaceList()
    self._showType = UIHeroRaceList.TYPE_NORMAL

    self._wndClass = nil
    self._uiListTrans = nil
    self._callbackFunc = nil
    self._checkSelFunc = nil
    self._checkRedPointFunc = nil

    --- 显示空种族图标
    self._noShowRaceList = {}

    self._ignoreRaceList = {}

    self._showListBg = false

    self._uiListKey = nil
end

function UIHeroRaceList:Create(data)
    local showType = data.showType or UIHeroRaceList.TYPE_NORMAL
    self._showType = showType

    self._wndClass = data.wndClass
    self._uiListTrans = data.listTrans
    self._callbackFunc = data.callbackFunc
    self._checkSelFunc = data.checkSelFunc
    self._checkRedPointFunc = data.checkRedPointFunc

    self._noShowRaceList = data.noShowRaceList or {}
    self._ignoreRaceList = data.ignoreRaceList or {}

    self._showListBg = data.showListBg and true or false

    self:RefreshShowType()

    self:InitHeroRaceList()
end

function UIHeroRaceList:SetCallBackFunc(callbackFunc)
    self._callbackFunc = callbackFunc
end

function UIHeroRaceList:SetCheckSelFunc(checkSelFunc)
    self._checkSelFunc = checkSelFunc
end
------------------------------------------------------------------
function UIHeroRaceList:RefreshShowType()
    if not self:IsValid() then return end
    local uiListTrans = self._uiListTrans
    local showType = self._showType
    local HeroRaceBgTrans = CS.FindTrans(uiListTrans,"HeroRaceBg")
    local isShowRaceBg = showType == UIHeroRaceList.TYPE_SHOWBG
    CS.ShowObject(HeroRaceBgTrans,isShowRaceBg)

    local ListBgTrans = CS.FindTrans(uiListTrans,"ListBg")
    CS.ShowObject(ListBgTrans,self._showListBg)
end

function UIHeroRaceList:RefreshHeroRaceList()
    if not self:IsValid() then return end
    if not self._uiListKey then return end
    local uiHeroRaceList = self._wndClass:FindUIScroll(self._uiListKey)
    if not uiHeroRaceList then return end
    local uiList = uiHeroRaceList:GetList()
   uiList:RefreshList()
end

function UIHeroRaceList:InitHeroRaceList()
    if not self:IsValid() then return end

    local wndClass = self._wndClass
    local uiListTrans = self._uiListTrans

    local key = uiListTrans:GetInstanceID()
    self._uiListKey = key

    local list = self:GetHeroRaceList()
    local uiList = wndClass:FindUIScroll(key)
    if uiList then
        uiList:RefreshList(list)
    else
        uiList = wndClass:GetUIScroll(key)
        uiList:Create(uiListTrans,list,function(...) self:OnDrawHeroRaceCell(...)  end)
    end
end

function UIHeroRaceList:CheckRaceIsShow(refId)
    local isHide = self._noShowRaceList[refId]
    return not isHide
end

function UIHeroRaceList:CheckHeroRaceRedPointStatus(refId)
    if not self._checkRedPointFunc then return false end
    return self._checkRedPointFunc(refId)
end

function UIHeroRaceList:OnDrawHeroRaceCell(list,item,itemdata,itempos)
    local RaceIconTrans = CS.FindTrans(item,"RaceIcon")
    local SelImgTrans = CS.FindTrans(item,"SelImg")
    local redPointTrans = CS.FindTrans(item,"redPoint")

    local refId = itemdata.refId
    local showRace = self:CheckRaceIsShow(refId)
    if showRace then
        self:SetIconImg(RaceIconTrans,itemdata.icon)
    end
    CS.ShowObject(RaceIconTrans,showRace)

    local isSel = self:CheckHeroRaceIsSel(refId)
    CS.ShowObject(SelImgTrans,isSel)

    local showRedPoint = self:CheckHeroRaceRedPointStatus(refId)
    CS.ShowObject(redPointTrans,showRedPoint)

    self:SetIconClick(RaceIconTrans,function()
        self:OnClickHeroRaceIconFunc(refId)
    end)
end

function UIHeroRaceList:OnClickHeroRaceIconFunc(refId)
    if self._callbackFunc then
        self._callbackFunc(refId)
    end
    self:RefreshHeroRaceList()
end
------------------------------------------------------------------

function UIHeroRaceList:SetIconImg(trans,img,func)
    if not self:IsValid() then return end
    self._wndClass:SetWndEasyImage(trans,img,func)
end

function UIHeroRaceList:SetIconClick(trans,func)
    if not self:IsValid() then return end
    self._wndClass:SetWndClick(trans,func)
end

------------------------------------------------------------------

function UIHeroRaceList:IsValid()
    if self:IsDestroy() then return false end

    local wndClass = self._wndClass
    if not wndClass then return false end
    if not wndClass:IsWndValid() then return false end

    local uiListTrans = self._uiListTrans
    if not CS.IsValidObject(uiListTrans) then return false end

    return true
end

------------------------------------------------------------------

function UIHeroRaceList:CheckHeroRaceIsSel(refId)
    if not self:IsValid() then return false end
    if not self._checkSelFunc then return false end
    return self._checkSelFunc(refId)
end

------------------------------------------------------------------

function UIHeroRaceList:CheckIsIgnore(refId)
    local ref = GameTable.CharacterRaceRef[refId]
    local treasureRaceShow = ref and GameTable.CharacterRaceRef[refId].treasureRaceShow == 1 or nil
    return self._ignoreRaceList[refId] or treasureRaceShow
end

function UIHeroRaceList:GetHeroRaceList()
    --新增排序规则
    local ref = gModelHero:GetHeroRaceRefSortByRank()
    local list = {}

    for k,v in pairs(ref) do
        if not self:CheckIsIgnore(v.refId) then
            table.insert(list,{
                refId = v.refId,
                icon = v.icon,
            })
        end
    end

    return list
end

------------------------------------------------------------------

function UIHeroRaceList:IsDestroy()
    return self._isDestroy
end

function UIHeroRaceList:Destroy()
    self._isDestroy = true
    table.removeall(self)
end

return UIHeroRaceList